import React from 'react';
import { WebView } from 'react-native-webview';

class MyWebComponent extends React.Component {
  constructor(props) {
    super(props);
    this.webview = null;
    window.ReactNativeWebView = {
      postMessage: (data) => {
        if (this.webview) {
          this.webview.postMessage(JSON.stringify(data));
        }
      },
    };
  }
  
  render() {
    return (
      <WebView
        ref={(ref) => { this.webview = ref; }}
        source={{ uri: 'https://www.yourwebsite.com' }}
        javaScriptEnabled={true}
        onMessage={event => {
          console.log('Received js message', event);
          // handle the received data here, you may need to parse it as JSON depending upon how your web content is sending it
        }}
      />
    );
  }
}